 public ServerRowViewModel(ServerDefinition d){Definition=d;status=d.Enabled?ServerStatus.Stopped:ServerStatus.Disabled;}public string Name=>Definition.Name;public string TypeText=>Definition.ServerType==ServerType.Nats?Definition.Location==ServerLocation.Remote?"NATS Remote":"NATS":"TIBCO RV";public string LocationText=>Definition.Location.ToString();public string Endpoint=>Definition.Location==ServerLocation.Remote?$"{(Definition.Nats.UseTls?"https":"http")}://{Definition.HealthCheckHost}:{Definition.Nats.MonitoringPort}/varz":"Local process";public string ExecutableDisplay=>Definition.Location==ServerLocation.Remote?Endpoint:Definition.Executable;public int PrimaryPort=>ServerValidator.GetPorts(Definition).FirstOrDefault(x=>x.HasValue)??0;public string Ports=>string.Join(", ",ServerValidator.GetPorts(Definition).Where(x=>x.HasValue));public string LogFile=>Definition.Location==ServerLocation.Remote?"Remote telemetry":Definition.LogFilePath??"—";public bool AutoStart=>Definition.StartWithApplication;
 public ServerStatus Status{get=>status;set{if(Set(ref status,value)){Raise(nameof(StatusText));Raise(nameof(StatusBrush));Raise(nameof(StatusTooltip));Raise(nameof(CanStart));Raise(nameof(CanStop));}}}public string StatusText=>Status.ToString();public string StatusTooltip=>$"{StatusText} — {Health}";public Brush StatusBrush=>Status switch{ServerStatus.Running=>Brushes.LimeGreen,ServerStatus.Starting or ServerStatus.Stopping or ServerStatus.Restarting=>Brushes.Goldenrod,ServerStatus.Failed or ServerStatus.Invalid=>Brushes.OrangeRed,ServerStatus.Stopped=>Brushes.SlateGray,_=>Brushes.DarkGray};
