 value){serverId=value.ServerId;serverVersion=value.Version;connections=value.Connections;subscriptions=value.Subscriptions;inMessages=value.InMessages;outMessages=value.OutMessages;inBytes=value.InBytes;outBytes=value.OutBytes;slowConsumers=value.SlowConsumers;Uptime=value.Uptime;Cpu=value.CpuPercent;Memory=value.MemoryBytes;Started=DateTime.Now-value.Uptime;Raise(nameof(RemoteMetricsSummary));}static string FormatBytes(long value)=>value>=1073741824?$"{value/1073741824d:F1} GB":value>=1048576?$"{value/1048576d:F1} MB":value>=1024?$"{value/1024d:F1} KB":$"{value} B";public void RefreshDefinition(){Raise(nameof(Name));Raise(nameof(TypeText));Raise(nameof(LocationText));Raise(nameof(Endpoint));Raise(nameof(ExecutableDisplay));Raise(nameof(PrimaryPort));Raise(nameof(Ports));Raise(nameof(LogFile));Raise(nameof(AutoStart));Raise(nameof(CanOpenLog));Raise(nameof(RemoteMetricsSummary));}
