 readonly PathResolver paths;readonly IConfigurationStore store;readonly ConfigurationTransferService transfer;readonly Dictionary<ServerType,IServerAdapter> adapters;readonly ProcessManager processes;readonly LogTailReader logs=new();readonly CancellationTokenSource shutdown=new();CancellationTokenSource monitoringIntervalChanged=new();readonly System.Windows.Threading.DispatcherTimer relativeTimeTimer=new(){Interval=TimeSpan.FromSeconds(1)};readonly HashSet<Guid> intentionalExits=[];ServerRowViewModel? selected;string logText="Select a server to view its log.";bool paused;DateTime lastUpdated;
 public ObservableCollection<ServerRowViewModel> Servers{get;}=[];public GlobalSettings Settings{get;}public ServerRowViewModel? Selected{get=>selected;set{if(Set(ref selected,value)){Raise(nameof(SelectedEffectiveArguments));Raise(nameof(SelectedConfigurationSummary));Raise(nameof(SelectedRemoteMetrics));RaiseCommands();_=RefreshLogAsync();}}}public string LogText{get=>logText;set=>Set(ref logText,value);}public bool IsLogPaused{get=>paused;set=>Set(ref paused,value);}public DateTime LastUpdated{get=>lastUpdated;set{if(Set(ref lastUpdated,value))Raise(nameof(LastUpdatedText));}}public string LastUpdatedText{get{if(LastUpdated==default)return "Waiting for first refresh";var age=DateTime.Now-LastUpdated;var relative=age.TotalSeconds<2?"just now":age.TotalSeconds<60?$"{(int)age.TotalSeconds}s ago":age.TotalMinutes<60?$"{(int)age.TotalMinutes}m ago":$"{(int)age.TotalHours}h ago";return $"Updated {relative} • every {Settings.MonitoringIntervalSeconds}s";}}public string SelectedEffectiveArguments{get{if(Selected is null)return "";if(Selected.Definition.Location==ServerLocation.Remote)return Selected.Endpoint;try{return adapters[Selected.Definition.ServerType].BuildStartInfo(Selected.Definition,Settings).Arguments;}catch(Exception ex){return "Unavailable: "+ex.Message;}}}public string SelectedRemoteMetrics=>Selected?.RemoteMetricsSummary??"Select a server.";public string SelectedConfigurationSummary=>Selected is null?"Select a server.":$"Name: {Selected.Name}\nType: {Selected.TypeText}\nLocation: {Selected.LocationText}\nEnabled: {Selected.Definition.Enabled}\nLaunch mode: {Selected.Definition.LaunchMode}\nExecutable / endpoint: {Selected.ExecutableDisplay}\nWorking directory: {Selected.Definition.WorkingDirectory}\nConfig file: {Selected.Definition.ConfigFilePath}\nLog file: {Selected.Definition.LogFilePath}\nPorts: {Selected.Ports}\nTLS: {Selected.Definition.Nats.UseTls}\nAuto start: {Selected.Definition.StartWithApplication}\nAuto restart: {Selected.Definition.AutoRestart}";
 public ICommand AddServerCommand{get;}public ICommand EditServerCommand{get;}public ICommand DeleteServerCommand{get;}public ICommand ImportConfigurationCommand{get;}public ICommand ExportConfigurationCommand{get;}public ICommand StartServerCommand{get;}public ICommand StopServerCommand{get;}public ICommand RestartServerCommand{get;}public ICommand OpenServerLogCommand{get;}public ICommand StartAllCommand{get;}public ICommand StopAllCommand{get;}public ICommand RestartAllCommand{get;}public ICommand RefreshCommand{get;}public ICommand OpenLogCommand{get;}public ICommand OpenLogFolderCommand{get;}public ICommand PauseLogCommand{get;}public ICommand ResumeLogCommand{get;}public ICommand ClearLogCommand{get;}public ICommand SettingsCommand{get;}
 public MainViewModel(PathResolver p,IConfigurationStore s,ConfigurationTransferService configurationTransfer,IEnumerable<IServerAdapter> a,GlobalSettings settings){paths=p;store=s;transfer=configurationTransfer;adapters=a.ToDictionary(x=>x.ServerType);Settings=settings;processes=new(a,settings);processes.ProcessExited+=OnExited;relativeTimeTimer.Tick+=(_,_)=>Raise(nameof(LastUpdatedText));relativeTimeTimer.Start();AddServerCommand=new AsyncRelayCommand(AddAsync);EditServerCommand=new AsyncRelayCommand(EditAsync,()=>Selected is not null&&!Selected.CanStop);DeleteServerCommand=new AsyncRelayCommand(DeleteAsync,()=>Selected is not null&&!Selected.CanStop);ImportConfigurationCommand=new AsyncRelayCommand(ImportConfigurationAsync,()=>!Servers.Any(x=>x.CanStop));ExportConfigurationCommand=new AsyncRelayCommand(ExportConfigurationAsync);StartServerCommand=new AsyncRelayCommand<ServerRowViewModel>(async r=>{if(r is not null)await StartAsync(r);},r=>r?.CanStart==true);StopServerCommand=new AsyncRelayCommand<ServerRowViewModel>(async r=>{if(r is not null)await StopAsync(r);},r=>r?.CanStop==true);RestartServerCommand=new AsyncRelayCommand<ServerRowViewModel>(async r=>{if(r is not null)await RestartAsync(r);},r=>r?.CanStop==true);OpenServerLogCommand=new RelayCommand<ServerRowViewModel>(r=>{if(r is not null){Selected=r;OpenPath(LogPath(r),false);}},r=>r?.CanOpenLog==true);StartAllCommand=new AsyncRelayCommand(()=>ForEachAsync(x=>x.CanStart,StartAsync),()=>Servers.Any(x=>x.CanStart));StopAllCommand=new AsyncRelayCommand(()=>ForEachAsync(x=>x.CanStop,StopAsync),()=>Servers.Any(x=>x.CanStop));RestartAllCommand=new AsyncRelayCommand(()=>ForEachAsync(x=>x.CanStop,RestartAsync),()=>Servers.Any(x=>x.CanStop));RefreshCommand=new AsyncRelayCommand(RefreshAllAsync);OpenLogCommand=new RelayCommand(()=>OpenPath(LogPath(Selected!),false),()=>Selected?.CanOpenLog==true);OpenLogFolderCommand=new RelayCommand(()=>OpenPath(LogPath(Selected!),true),()=>Selected?.CanOpenLog==true);PauseLogCommand=new RelayCommand(PauseLog,()=>!IsLogPaused);ResumeLogCommand=new RelayCommand(ResumeLog,()=>IsLogPaused);ClearLogCommand=new RelayCommand(()=>LogText="");SettingsCommand=new AsyncRelayCommand(EditSettingsAsync);}
 public async Task InitializeAsync(){Directory.CreateDirectory(paths.Resolve(Settings.LoggingRootDirectory));Directory.CreateDirectory(paths.Resolve("sample-config"));await EnsureSamplesAsync();var envelope=await store.LoadAsync("servers.json",new ConfigurationEnvelope<List<ServerDefinition>>{Data=null!});var defs=envelope.Data??await store.LoadAsync("servers.json",Defaults());foreach(var d in defs)Servers.Add(new(d));if(envelope.Data is null)await SaveAsync();var runtime=await store.LoadAsync("runtime.json",new ConfigurationEnvelope<List<RuntimeProcessState>>{Data=[]});foreach(var state in runtime.Data){var row=Servers.FirstOrDefault(x=>x.Definition.Id==state.ServerId);if(row is null)continue;row.LastExitCode=state.LastExitCode;row.LastExitTime=state.LastExitTimeUtc?.ToLocalTime();row.RestartCount=state.RestartCount;if(row.Definition.Location==ServerLocation.Local&&state.ProcessId>0&&processes.TryRecover(row.Definition,state))await RefreshAsync(row);}Selected=Servers.FirstOrDefault();if(Settings.AutoStartEnabledServers)foreach(var r in Servers.Where(x=>x.CanStart&&x.Definition.StartWithApplication&&processes.Get(x.Definition.Id) is null))await StartAsync(r);await RefreshAllAsync();await SaveRuntimeAsync();_=MonitorLoopAsync(shutdown.Token);}
 async Task EnsureSamplesAsync(){var n=paths.Resolve("sample-config/nats-server.conf");if(!File.Exists(n))await File.WriteAllTextAsync(n,"server_name: local-nats\nport: 4222\nhttp: 8222\nlog_file: 'logs/nats/local-nats.log'\ndebug: false\ntrace: false\n");var r=paths.Resolve("sample-config/rvdaemon.args.txt");if(!File.Exists(r))await File.WriteAllTextAsync(r,"# Verify flags against your installed TIBCO RV version\n-service 7500 -http 7580\n");}
 static List<ServerDefinition> Defaults()=>[new(){Name="Local NATS",Enabled=false,Executable="nats-server.exe",LaunchMode=LaunchMode.ConfigFile,ConfigFilePath="sample-config/nats-server.conf",LogFilePath="nats/local-nats.log",Nats=new(){ServerName="local-nats",ClientPort=4222,MonitoringPort=8222}},new(){Name="Local RV Daemon",ServerType=ServerType.TibcoRendezvous,Enabled=false,Executable="rvdaemon.exe",LaunchMode=LaunchMode.ManagedOptions,LogFilePath="tibrv/local-rvdaemon.log",TibRv=new(){Service=7500,HttpAdministrationPort=7580}}];
 async Task MonitorLoopAsync(CancellationToken ct){try{while(!ct.IsCancellationRequested){var changed=monitoringIntervalChanged.Token;using var wait=CancellationTokenSource.CreateLinkedTokenSource(ct,changed);try{await Task.Delay(TimeSpan.FromSeconds(Math.Max(1,Settings.MonitoringIntervalSeconds)),wait.Token);}catch(OperationCanceledException)when(changed.IsCancellationRequested&&!ct.IsCancellationRequested){continue;}await RefreshAllAsync();if(!IsLogPaused)await RefreshLogAsync();}}catch(OperationCanceledException)when(ct.IsCancellationRequested){}}void ApplyMonitoringIntervalImmediately(){var previous=Interlocked.Exchange(ref monitoringIntervalChanged,new CancellationTokenSource());previous.Cancel();previous.Dispose();Raise(nameof(LastUpdatedText));}
 async Task RefreshAllAsync(){foreach(var r in Servers)await RefreshAsync(r);LastUpdated=DateTime.Now;}async Task RefreshAsync(ServerRowViewModel r){r.LastChecked=DateTime.Now;if(!r.Definition.Enabled){r.Pid=null;r.Cpu=0;r.Memory=0;r.Status=ServerStatus.Disabled;r.Health="Disabled";return;}if(r.Definition.Location==ServerLocation.Remote){await RefreshRemoteAsync(r);return;}var m=processes.Get(r.Definition.Id);if(m is null){r.Pid=null;r.Cpu=0;r.Memory=0;var validation=ServerValidator.Validate(r.Definition,Servers.Select(x=>x.Definition),paths.Resolve);r.Status=validation.IsValid?ServerStatus.Stopped:ServerStatus.Invalid;r.Health=validation.IsValid?"Process is stopped.":string.Join(" ",validation.Errors);return;}try{var p=m.Process;var now=DateTime.UtcNow;var started=p.StartTime.ToUniversalTime();var cpu=p.TotalProcessorTime;r.Cpu=CpuUsageCalculator.Calculate(cpu-m.PreviousCpu,now-m.PreviousSampleUtc,Environment.ProcessorCount);m.PreviousCpu=cpu;m.PreviousSampleUtc=now;r.Pid=p.Id;r.Started=started.ToLocalTime();r.Uptime=now-started;r.Memory=p.WorkingSet64;var h=await adapters[r.Definition.ServerType].CheckHealthAsync(r.Definition,new(p.Id,started,r.Definition.Executable),shutdown.Token);r.Health=h.Message;if(h.IsHealthy){r.Status=ServerStatus.Running;r.LastError=null;}else if(r.Uptime<TimeSpan.FromSeconds(Math.Max(0,r.Definition.HealthCheckGracePeriodSeconds)))r.Status=ServerStatus.Starting;else{r.Status=ServerStatus.Failed;r.LastError=h.Message;}}catch(OperationCanceledException)when(shutdown.IsCancellationRequested){}catch(Exception ex){r.LastError=ex.Message;r.Status=ServerStatus.Failed;}}async Task RefreshRemoteAsync(ServerRowViewModel r){r.Pid=null;var validation=ServerValidator.Validate(r.Definition,Servers.Select(x=>x.Definition),paths.Resolve);if(!validation.IsValid){r.Status=ServerStatus.Invalid;r.Health=string.Join(" ",validation.Errors);return;}try{if(adapters[r.Definition.ServerType] is not IRemoteServerMonitor monitor)throw new NotSupportedException("This server type does not support remote monitoring.");var telemetry=await monitor.GetTelemetryAsync(r.Definition,shutdown.Token);r.ApplyTelemetry(telemetry);r.Status=ServerStatus.Running;r.Health=$"Remote NATS {(r.Definition.Nats.UseTls?"HTTPS":"HTTP")} /varz healthy";r.LastError=null;if(Selected==r)Raise(nameof(SelectedRemoteMetrics));}catch(OperationCanceledException)when(shutdown.IsCancellationRequested){}catch(Exception ex){r.Status=ServerStatus.Failed;r.Health="Remote /varz unavailable";r.LastError=ex.Message;}}
 async Task StartAsync(ServerRowViewModel r){var v=ServerValidator.Validate(r.Definition,Servers.Select(x=>x.Definition),paths.Resolve);if(!v.IsValid){MessageBox.Show(string.Join("\n",v.Errors),"Cannot start",MessageBoxButton.OK,MessageBoxImage.Warning);return;}try{r.Status=ServerStatus.Starting;await processes.StartAsync(r.Definition,shutdown.Token);await RefreshAsync(r);await SaveRuntimeAsync();}catch(Exception ex){r.LastError=ex.Message;r.Status=ServerStatus.Failed;}RaiseCommands();}async Task StopAsync(ServerRowViewModel r){if(Settings.ConfirmForceKill&&r.Definition.ForceKillAfterTimeout&&MessageBox.Show("If graceful shutdown times out, the process tree will be force-killed. Continue?","Stop server",MessageBoxButton.YesNo,MessageBoxImage.Warning)!=MessageBoxResult.Yes)return;intentionalExits.Add(r.Definition.Id);r.Status=ServerStatus.Stopping;var x=await processes.StopAsync(r.Definition,shutdown.Token);if(!x.Stopped){intentionalExits.Remove(r.Definition.Id);r.LastError=x.Error;r.Status=ServerStatus.Failed;}else r.Status=ServerStatus.Stopped;await SaveRuntimeAsync();RaiseCommands();}async Task RestartAsync(ServerRowViewModel r){intentionalExits.Add(r.Definition.Id);r.Status=ServerStatus.Restarting;try{await processes.RestartAsync(r.Definition,shutdown.Token);r.RestartCount++;await RefreshAsync(r);await SaveRuntimeAsync();}catch(Exception ex){intentionalExits.Remove(r.Definition.Id);r.LastError=ex.Message;r.Status=ServerStatus.Failed;}RaiseCommands();}async Task ForEachAsync(Func<ServerRowViewModel,bool> f,Func<ServerRowViewModel,Task>a){foreach(var r in Servers.Where(f).ToList())await a(r);}
 async Task AddAsync(){var d=new ServerDefinition{GracefulStopTimeoutSeconds=Settings.DefaultGracefulStopTimeoutSeconds,ForceKillAfterTimeout=Settings.DefaultForceKillPolicy};var w=new ServerEditorWindow(d,Servers.Select(x=>x.Definition).ToList(),paths);if(w.ShowDialog()==true){Servers.Add(new(d));Selected=Servers[^1];await SaveWithErrorAsync(SaveAsync);}}async Task EditAsync(){if(Selected is null)return;var c=Selected.Definition.Clone();var w=new ServerEditorWindow(c,Servers.Select(x=>x.Definition).ToList(),paths);if(w.ShowDialog()==true){Copy(c,Selected.Definition);Selected.RefreshDefinition();Raise(nameof(SelectedEffectiveArguments));Raise(nameof(SelectedConfigurationSummary));await SaveWithErrorAsync(SaveAsync);}}async Task DeleteAsync(){if(Selected is null)return;if(Selected.CanStop){MessageBox.Show("Stop the server before deleting it.","Server is running",MessageBoxButton.OK,MessageBoxImage.Warning);return;}if(MessageBox.Show($"Delete '{Selected.Name}'?","Confirm deletion",MessageBoxButton.YesNo,MessageBoxImage.Warning)!=MessageBoxResult.Yes)return;Servers.Remove(Selected);Selected=Servers.FirstOrDefault();await SaveWithErrorAsync(SaveAsync);}async Task ExportConfigurationAsync(){var dialog=new SaveFileDialog{Title="Export Messaging Server Manager configuration",Filter="Messaging Server Manager configuration (*.msmconfig.json)|*.msmconfig.json|JSON files (*.json)|*.json",FileName=$"MessagingServerManager-{DateTime.Now:yyyyMMdd-HHmmss}.msmconfig.json",AddExtension=true,DefaultExt=".json"};if(dialog.ShowDialog()!=true)return;try{await transfer.ExportAsync(dialog.FileName,new PortableConfigurationBundle{Settings=Settings,Servers=Servers.Select(x=>x.Definition).ToList()});MessageBox.Show("Configuration exported successfully.","Export complete",MessageBoxButton.OK,MessageBoxImage.Information);}catch(Exception ex){MessageBox.Show("Configuration could not be exported: "+ex.Message,"Export failed",MessageBoxButton.OK,MessageBoxImage.Error);}}async Task ImportConfigurationAsync(){if(Servers.Any(x=>x.CanStop)){MessageBox.Show("Stop all managed servers before importing configuration.","Import unavailable",MessageBoxButton.OK,MessageBoxImage.Warning);return;}var dialog=new OpenFileDialog{Title="Load Messaging Server Manager configuration",Filter="Messaging Server Manager configuration (*.msmconfig.json)|*.msmconfig.json|JSON files (*.json)|*.json"};if(dialog.ShowDialog()!=true)return;try{var bundle=await transfer.ImportAsync(dialog.FileName);var errors=ValidateBundle(bundle);if(errors.Count>0){MessageBox.Show(string.Join(Environment.NewLine,errors),"Invalid configuration",MessageBoxButton.OK,MessageBoxImage.Warning);return;}if(MessageBox.Show($"Replace the current configuration with {bundle.Servers.Count} imported server definition(s)?","Confirm import",MessageBoxButton.YesNo,MessageBoxImage.Warning)!=MessageBoxResult.Yes)return;CopySettings(bundle.Settings,Settings);ApplyMonitoringIntervalImmediately();Servers.Clear();foreach(var definition in bundle.Servers)Servers.Add(new ServerRowViewModel(definition));Selected=Servers.FirstOrDefault();await store.SaveAsync("settings.json",Settings);await SaveAsync();await SaveRuntimeAsync();await RefreshAllAsync();MessageBox.Show("Configuration loaded successfully.","Import complete",MessageBoxButton.OK,MessageBoxImage.Information);}catch(Exception ex){MessageBox.Show("Configuration could not be loaded: "+ex.Message,"Import failed",MessageBoxButton.OK,MessageBoxImage.Error);}}List<string> ValidateBundle(PortableConfigurationBundle bundle){var errors=new List<string>();if(string.IsNullOrWhiteSpace(bundle.Settings.LoggingRootDirectory))errors.Add("Logging root directory is required.");if(bundle.Settings.MonitoringIntervalSeconds<1)errors.Add("Monitoring interval must be at least one second.");if(bundle.Settings.MaximumLogLines<1)errors.Add("Maximum log lines must be at least one.");foreach(var server in bundle.Servers)foreach(var error in ServerValidator.Validate(server,bundle.Servers,paths.Resolve).Errors)errors.Add($"{server.Name}: {error}");return errors.Distinct().ToList();}static void Copy(ServerDefinition s,ServerDefinition d){var c=System.Text.Json.JsonSerializer.Deserialize<ServerDefinition>(System.Text.Json.JsonSerializer.Serialize(s))!;foreach(var p in typeof(ServerDefinition).GetProperties().Where(x=>x.CanWrite))p.SetValue(d,p.GetValue(c));}Task SaveAsync()=>store.SaveAsync("servers.json",new ConfigurationEnvelope<List<ServerDefinition>>{Data=Servers.Select(x=>x.Definition).ToList()});Task SaveRuntimeAsync(){var running=processes.GetRuntimeStates().ToDictionary(x=>x.ServerId);var states=Servers.Select(row=>{var state=running.GetValueOrDefault(row.Definition.Id)??new RuntimeProcessState{ServerId=row.Definition.Id,Executable=row.Definition.Executable};state.LastExitCode=row.LastExitCode;state.LastExitTimeUtc=row.LastExitTime?.ToUniversalTime();state.RestartCount=row.RestartCount;return state;}).ToList();return store.SaveAsync("runtime.json",new ConfigurationEnvelope<List<RuntimeProcessState>>{Data=states});}async Task EditSettingsAsync(){var copy=System.Text.Json.JsonSerializer.Deserialize<GlobalSettings>(System.Text.Json.JsonSerializer.Serialize(Settings))!;var w=new SettingsWindow(copy);if(w.ShowDialog()==true){CopySettings(copy,Settings);ApplyMonitoringIntervalImmediately();await SaveWithErrorAsync(()=>store.SaveAsync("settings.json",Settings));}}static void CopySettings(GlobalSettings source,GlobalSettings target){foreach(var p in typeof(GlobalSettings).GetProperties().Where(x=>x.CanWrite))p.SetValue(target,p.GetValue(source));}static async Task SaveWithErrorAsync(Func<Task> save){try{await save();}catch(Exception ex){MessageBox.Show("Configuration could not be saved: "+ex.Message,"Save failed",MessageBoxButton.OK,MessageBoxImage.Error);}}
 string LogPath(ServerRowViewModel r){var p=r.Definition.LogFilePath!;return Path.IsPathRooted(Environment.ExpandEnvironmentVariables(p))?paths.Resolve(p):paths.Resolve(Path.Combine(Settings.LoggingRootDirectory,p));}async Task RefreshLogAsync(){if(Selected?.Definition.Location==ServerLocation.Remote){LogText="Remote monitoring does not provide access to the server log file.";return;}if(Selected is null||string.IsNullOrWhiteSpace(Selected.Definition.LogFilePath)){LogText="No log file is configured.";return;}try{LogText=string.Join(Environment.NewLine,await logs.ReadTailAsync(LogPath(Selected),Settings.MaximumLogLines,shutdown.Token));}catch(Exception ex){LogText="Unable to read log: "+ex.Message;}}void PauseLog(){IsLogPaused=true;RaiseCommands();}void ResumeLog(){IsLogPaused=false;RaiseCommands();_=RefreshLogAsync();}static void OpenPath(string p,bool folder){var t=folder?(Directory.Exists(p)?p:Path.GetDirectoryName(p)!):p;if(folder)Directory.CreateDirectory(t);try{Process.Start(new ProcessStartInfo(t){UseShellExecute=true});}catch(Exception ex){MessageBox.Show(ex.Message,"Open failed");}}void OnExited(Guid id,int? code)=>Application.Current.Dispatcher.Invoke(async()=>{var r=Servers.FirstOrDefault(x=>x.Definition.Id==id);if(r is null)return;var intentional=intentionalExits.Remove(id);r.LastExitCode=code;r.LastExitTime=DateTime.Now;r.Status=intentional?ServerStatus.Stopped:ServerStatus.Failed;r.Pid=null;if(!intentional)r.LastError=$"Process exited unexpectedly with code {(code?.ToString()??"unknown")}.";await SaveRuntimeAsync();RaiseCommands();if(!intentional&&!shutdown.IsCancellationRequested&&r.Definition.Enabled&&r.Definition.AutoRestart){r.RestartCount++;await Task.Delay(1000);await StartAsync(r);}});void RaiseCommands(){if(EditServerCommand is AsyncRelayCommand edit)edit.Raise();if(DeleteServerCommand is AsyncRelayCommand delete)delete.Raise();if(ImportConfigurationCommand is AsyncRelayCommand import)import.Raise();foreach(var c in new[]{StartAllCommand,StopAllCommand,RestartAllCommand})if(c is AsyncRelayCommand bulk)bulk.Raise();foreach(var c in new[]{OpenLogCommand,OpenLogFolderCommand,PauseLogCommand,ResumeLogCommand})if(c is RelayCommand r)r.Raise();if(StartServerCommand is AsyncRelayCommand<ServerRowViewModel> start)start.Raise();if(StopServerCommand is AsyncRelayCommand<ServerRowViewModel> stop)stop.Raise();if(RestartServerCommand is AsyncRelayCommand<ServerRowViewModel> restart)restart.Raise();if(OpenServerLogCommand is RelayCommand<ServerRowViewModel> log)log.Raise();}public void Dispose(){relativeTimeTimer.Stop();shutdown.Cancel();monitoringIntervalChanged.Cancel();monitoringIntervalChanged.Dispose();processes.Dispose();shutdown.Dispose();}
